// SPDX-License-Identifier: MIT

pragma solidity ^0.8.0;

contract DayCounter {

function daysSince(uint epochTime) public view returns
(uint) {

uint secondsPassed = block.timestamp - epochTime;

uint daysPassed = secondsPassed / 86400;

return daysPassed;

}

}

